# Dimensions assessment scoring model

from dataclasses import dataclass, field
from typing import Literal

Level = Literal[1, 2, 3, 4, 5]

@dataclass
class IndicatorScore:
    dimension: str
    indicator: str
    score: Level
    evidence: str       # Brief description of evidence observed

@dataclass
class DimensionAssessment:
    dimension: str
    indicators: list[IndicatorScore]

    def score(self) -> float:
        if not self.indicators:
            return 0.0
        return sum(i.score for i in self.indicators) / len(self.indicators)

    def internal_consistency(self) -> float:
        scores = [i.score for i in self.indicators]
        return max(scores) - min(scores)

@dataclass
class MaturityProfile:
    organization: str
    assessment_date: str
    dimensions: list[DimensionAssessment] = field(default_factory=list)

    def dimension_scores(self) -> dict[str, float]:
        return {d.dimension: round(d.score(), 2) for d in self.dimensions}

    def binding_constraint(self) -> str:
        scores = self.dimension_scores()
        return min(scores, key=scores.get)

    def overall_score(self) -> float:
        scores = list(self.dimension_scores().values())
        return round(sum(scores) / len(scores), 2) if scores else 0.0
